24	/**
25	 * Add a blockage entry to BOTH maps (blockedBy and blocks).
26	 * Creates entries with status "active".
27	 * Idempotent: if an identical active entry already exists, no duplicate is added.
28	 */
29	export function addBlockage(
30	  deps: DependenciesFile,
31	  blockedId: IssueId,
32	  blockerId: IssueId,
33	): DependenciesFile {
34	  const entry: BlockageEntry = { blockerId, blockedId, status: "active" };
35	
36	  // Check for duplicate active entry in blockedBy
37	  const existingBlockedBy = deps.blockedBy[blockedId] ?? [];
38	  const alreadyExists =
39	    existingBlockedBy.some(
40	      (e) => e.blockerId === blockerId && e.blockedId === blockedId && e.status === "active",
41	    ) &&
42	    (deps.blocks[blockerId] ?? []).some(
43	      (e) => e.blockerId === blockerId && e.blockedId === blockedId && e.status === "active",
44	    );
45	
46	  if (alreadyExists) {
47	    return deps;
48	  }
49	
50	  const newBlockedBy = {
51	    ...deps.blockedBy,
52	    [blockedId]: [...existingBlockedBy, entry],
53	  };
54	
55	  const existingBlocks = deps.blocks[blockerId] ?? [];
56	  const newBlocks = {
57	    ...deps.blocks,
58	    [blockerId]: [...existingBlocks, entry],
59	  };
60	
61	  return { blockedBy: newBlockedBy, blocks: newBlocks };
62	}
63	
64	/**
65	 * Mark a blockage as resolved in both maps.
66	 * Idempotent: if entry is already resolved or doesn't exist, no error.
67	 */
68	export function resolveBlockage(
69	  deps: DependenciesFile,
70	  blockedId: IssueId,
71	  blockerId: IssueId,
72	): DependenciesFile {
73	  // Resolve in blockedBy map
74	  const blockedByEntries = deps.blockedBy[blockedId];
75	  let newBlockedBy = { ...deps.blockedBy };
76	  if (blockedByEntries) {
77	    newBlockedBy = {
78	      ...deps.blockedBy,
79	      [blockedId]: blockedByEntries.map((e) =>
80	        e.blockerId === blockerId && e.blockedId === blockedId ? { ...e, status: "resolved" } : e,
81	      ),
82	    };
83	  }
84	
85	  // Resolve in blocks map
86	  const blocksEntries = deps.blocks[blockerId];
87	  let newBlocks = { ...deps.blocks };
88	  if (blocksEntries) {
89	    newBlocks = {
90	      ...deps.blocks,
91	      [blockerId]: blocksEntries.map((e) =>
92	        e.blockerId === blockerId && e.blockedId === blockedId ? { ...e, status: "resolved" } : e,
93	      ),
94	    };
95	  }
96	
97	  return { blockedBy: newBlockedBy, blocks: newBlocks };
98	}
99	
100	/**
101	 * Remove a blockage entry entirely from both maps.
102	 * Idempotent: if entry doesn't exist, no error.
103	 */
104	export function deleteBlockage(
105	  deps: DependenciesFile,
106	  blockedId: IssueId,
107	  blockerId: IssueId,
108	): DependenciesFile {
109	  // Remove from blockedBy map
110	  let newBlockedBy = { ...deps.blockedBy };
111	  const blockedByEntries = deps.blockedBy[blockedId];
112	  if (blockedByEntries) {
113	    const filtered = blockedByEntries.filter(
114	      (e) => !(e.blockerId === blockerId && e.blockedId === blockedId),
115	    );
116	    if (filtered.length === 0) {
117	      const { [blockedId]: _, ...rest } = newBlockedBy;
118	      newBlockedBy = rest;
119	    } else {
120	      newBlockedBy = { ...deps.blockedBy, [blockedId]: filtered };
121	    }
122	  }
123	
124	  // Remove from blocks map
125	  let newBlocks = { ...deps.blocks };
126	  const blocksEntries = deps.blocks[blockerId];
127	  if (blocksEntries) {
128	    const filtered = blocksEntries.filter(
129	      (e) => !(e.blockerId === blockerId && e.blockedId === blockedId),
130	    );
131	    if (filtered.length === 0) {
132	      const { [blockerId]: _, ...rest } = newBlocks;
133	      newBlocks = rest;
134	    } else {
135	      newBlocks = { ...deps.blocks, [blockerId]: filtered };
136	    }
137	  }
138	
139	  return { blockedBy: newBlockedBy, blocks: newBlocks };
140	}
141	
142	/**
143	 * Count active entries in blocks[issueId] — used for impact score.
144	 */
145	export function getImpactScore(deps: DependenciesFile, issueId: IssueId): number {
146	  const blocks = deps.blocks[issueId];
147	  if (!blocks) return 0;
148	  return blocks.filter((entry) => entry.status === "active").length;
149	}
150	
151	/**
152	 * Detect if adding blockedId→blockerId would create a cycle.
153	 * Walk blockedBy graph transitively from blockerId.
154	 * If blockedId is reached at any point → cycle detected.
155	 * Only considers entries with status === "active".
156	 */
157	export function detectCycle(
158	  deps: DependenciesFile,
159	  blockedId: IssueId,
160	  blockerId: IssueId,
161	): boolean {
162	  const visited = new Set<IssueId>();
163	  const queue: IssueId[] = [blockerId];
164	
165	  while (queue.length > 0) {
166	    const current = queue.shift()!;
167	
168	    if (current === blockedId) return true;
169	    if (visited.has(current)) continue;
170	    visited.add(current);
171	
172	    const blockedByCurrent = deps.blockedBy[current] ?? [];
173	    for (const entry of blockedByCurrent) {
174	      if (entry.status === "active") {
175	        queue.push(entry.blockerId);
176	      }
177	    }
178	  }
179	
180	  return false;
181	}
