13	describe("dependency-manager", () => {
14	  describe("addBlockage", () => {
15	    test("adds entry to both maps with active status", () => {
16	      const result = addBlockage(EMPTY_DEPS, "issue0001", "issue0002");
17	
18	      // blockedBy["issue0001"] should have entry
19	      expect(result.blockedBy["issue0001"]).toHaveLength(1);
