138	    test("for issue with no blocks: returns 0", () => {
139	      expect(getImpactScore(EMPTY_DEPS, "issue0001")).toBe(0);
140	    });
141	
142	    test("ignores resolved entries", () => {
143	      let deps = addBlockage(EMPTY_DEPS, "issue0001", "blocker01");
144	      deps = addBlockage(deps, "issue0002", "blocker01");
145	      deps = resolveBlockage(deps, "issue0001", "blocker01");
