151	
152	  describe("detectCycle", () => {
153	    test("direct cycle: A blocks B, B blocks A → detected", () => {
154	      // issue0001 is blocked by issue0002
155	      const deps = addBlockage(EMPTY_DEPS, "issue0001", "issue0002");
156	      // Now check if adding issue0002 blocked by issue0001 would be a cycle
157	      expect(detectCycle(deps, "issue0002", "issue0001")).toBe(true);
158	    });
159	
160	    test("transitive cycle: A blocks B, B blocks C, C blocks A → detected", () => {
161	      // A blocked by B, B blocked by C
162	      const step1 = addBlockage(EMPTY_DEPS, "issueA0000", "issueB0000");
163	      const deps = addBlockage(step1, "issueB0000", "issueC0000");
164	      // Would adding C blocked by A be a cycle?
165	      // Walk from A through blockedBy: A → B → C, then check if C blockedBy reaches A
166	      // Actually: detectCycle(deps, blockedId=C, blockerId=A)
167	      // Walk blockedBy from A: blockedBy[A] has B (active), walk to B, blockedBy[B] has C (active), walk to C
168	      // Check: does C === C (blockedId)? Yes → cycle!
169	      expect(detectCycle(deps, "issueC0000", "issueA0000")).toBe(true);
170	    });
171	
172	    test("no cycle: A blocks B, C blocks D → not detected", () => {
173	      const step1 = addBlockage(EMPTY_DEPS, "issueA0000", "issueB0000");
174	      const deps = addBlockage(step1, "issueC0000", "issueD0000");
175	
176	      // Would adding D blocked by B be a cycle?
177	      // Walk from B through blockedBy: blockedBy[B] → undefined → no cycle
178	      expect(detectCycle(deps, "issueD0000", "issueB0000")).toBe(false);
179	    });
180	
181	    test("ignores resolved entries", () => {
182	      let deps = addBlockage(EMPTY_DEPS, "issue0001", "issue0002");
183	      deps = resolveBlockage(deps, "issue0001", "issue0002");
184	
185	      // Resolved, so no cycle should be detected
186	      expect(detectCycle(deps, "issue0002", "issue0001")).toBe(false);
187	    });
188	
189	    test("self-block: A blocks A → detected", () => {
190	      const deps = addBlockage(EMPTY_DEPS, "issue0001", "issue0001");
191	      // Adding issue0001 blocked by issue0001 would be detected by detectCycle
192	      // blockedId=issue0001, blockerId=issue0001
193	      // Walk from issue0001: current=issue0001, check if === blockedId(issue0001) → true → cycle!
194	      expect(detectCycle(deps, "issue0001", "issue0001")).toBe(true);
195	    });
