197	    test("no cycle with same blocker used by multiple issues", () => {
198	      let deps = addBlockage(EMPTY_DEPS, "issue0001", "blocker01");
199	      deps = addBlockage(deps, "issue0002", "blocker01");
200	
201	      // Would adding blocker01 blocked by issue0003 be a cycle?
202	      // Walk from issue0003 through blockedBy: blockedBy[issue0003] → undefined → no cycle
203	      expect(detectCycle(deps, "blocker01", "issue0003")).toBe(false);
204	    });
205	  });
206	});
